class.referenceSrc:
def solve(arr):
    if not arr:
        return [0, -1]
    best_start = 0
    best_len = 1
    cur_start = 0
    cur_len = 1
    for i in range(1, len(arr)):
        if arr[i] > arr[i - 1]:
            cur_len += 1
        else:
            if cur_len > best_len:
                best_len = cur_len
                best_start = cur_start
            cur_start = i
            cur_len = 1
    if cur_len > best_len:
        best_len = cur_len
        best_start = cur_start
    return [best_start, best_start + best_len - 1]

