def check(arr, output):
    if not isinstance(output, list) or len(output) != 2:
        return False
    s, e = output
    if not isinstance(s, int) or not isinstance(e, int):
        return False
    if not arr:
        return s == 0 and e == -1
    n = len(arr)
    if s < 0 or e < 0 or s >= n or e >= n or e < s:
        return False
    # Check strict increase
    for i in range(s, e):
        if arr[i] >= arr[i + 1]:
            return False
    reported_len = e - s + 1
    # Compute true max length and earliest start
    best_len = 1
    best_start = 0
    cur_start = 0
    cur_len = 1
    for i in range(1, n):
        if arr[i] > arr[i - 1]:
            cur_len += 1
        else:
            if cur_len > best_len:
                best_len = cur_len
                best_start = cur_start
            cur_start = i
            cur_len = 1
    if cur_len > best_len:
        best_len = cur_len
        best_start = cur_start
    if reported_len != best_len:
        return False
    if s != best_start:
        return False
    return True

